vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vUv.x += 0.02 * (texture( sampler_noise_lq,
                         vUv*0.050*texsize_noise_lq.zw*uTexSize.xy*2
                         + vec2(roam_cos.x,roam_sin.x)*0.1 ).y*2-1)*uAspect.x;
    vUv.x += 0.04 * (texture( sampler_noise_lq,
                         vUv*0.025*texsize_noise_lq.zw*uTexSize.xy*0.5
                         + vec2(roam_sin.y,-roam_cos.y)*0.03  ).z*2-1)*uAspect.x;

    ret = texture( sampler_main, vUv ).xyz;

    // darken over uTime
    //ret.z -= 0.004;
    ret.z *= 0.97;

